<template>
  <Loading
      v-if="loading"
      v-model:active="loading"
      :can-cancel="false"
      :is-full-page="true"
      color="#4785FE"
      loader="dots"
  />
  <div v-else class="bg-white p-3 rounded-md shadow calendar">
    <FullCalendar ref="calendarRef" :options="calendarOptions"/>
  </div>
</template>

<script setup>
import Loading from 'vue-loading-overlay';
import 'vue-loading-overlay/dist/vue-loading.css';
import {defineComponent, onMounted, ref, watch} from 'vue';
import '@fullcalendar/core/vdom' // solves problem with Vite
import FullCalendar from '@fullcalendar/vue3'
import '../assets/customCalendar.css'

const calendarRef = ref()
import {useI18n} from "vue-i18n";

const route = useRoute()

const {t, locale, messages} = useI18n()
const {calendarOptions, setCalendarApi, currentPeriod, setEvents} = useCalendarOptions(route)


import {useRoute} from "vue-router";
import {useStore} from "vuex";
import useCalendarOptions from "../hooks/useCalendarOptions";
import axios from "../plugins/axios";
import moment from "moment";


const store = useStore()

const loading = ref(false)

defineComponent({
  Loading, FullCalendar
})

watch(() => currentPeriod.value, async () => {
  await fetchTeenagers()
})

const fetchTeenagers = async (params) => {
  const resp = (await axios.get('api/event/all', {
    params: {
      month: currentPeriod.value || moment(new Date()).format('MM-YYYY'),
      viceId: route.params.id && route.params.id !=="undefined" ? route.params.id :""
    }
  })).data
  setEvents(resp.data)
}

watch(() => route.path, async () => {
  if (route.path.split("/")[1]==="vice") {
    await fetchTeenagers()
  }
})

onMounted(async () => {
  const calendarApi = calendarRef.value?.getApi()
  setCalendarApi(calendarApi)
})

</script>

<style scoped>
.calendar {
  min-height: 100%;
  display: flex;
  flex-direction: column;
}
</style>

